import React from "react";

const InternshipCard = ({ internship, userRole, applicationStatus, onApply, onEdit, onDelete }) => {
  return (
    <div style={{ border: "1px solid #ccc", padding: "16px", marginBottom: "16px", backgroundColor: "#f9f9f9" }}>
      <h2>{internship.title}</h2>
      <p><strong>Company:</strong> {internship.company}</p>
      <p><strong>Location:</strong> {internship.location}</p>
      <p><strong>Stipend:</strong> {internship.stipend}</p>
      <p><strong>Duration:</strong> {internship.duration}</p>
      <p><strong>Description:</strong> {internship.description}</p>
      <p><strong>Requirements:</strong> {internship.requirements}</p>
      <p><strong>Apply By:</strong> {internship.applyBy}</p>

      {userRole === "Student" && (
        <button onClick={() => onApply(internship._id)}>
          {applicationStatus === "Not Applied" ? "Apply" : applicationStatus}
        </button>
      )}

      {(userRole === "Admin" || userRole === "HR") && (
        <>
          <button onClick={() => onEdit(internship)}>Edit</button>
          <button onClick={() => onDelete(internship._id)}>Delete</button>
        </>
      )}
    </div>
  );
};

export default InternshipCard;
